class Solution:
    def findMaxLength(self, nums: List[int]) -> int:
        first = {0: -1}
        s = ans = 0
        for i, x in enumerate(nums):
            s += 1 if x else -1
            if s in first:
                ans = max(ans, i - first[s])
            else:
                first[s] = i
        return ans

