class Solution {
public:
    int findMaxLength(vector<int>& nums) {
        unordered_map<int,int> first{{0,-1}};
        int s = 0, ans = 0;
        for (int i = 0; i < (int)nums.size(); i++) {
            s += nums[i] ? 1 : -1;
            if (first.count(s)) ans = max(ans, i - first[s]);
            else first[s] = i;
        }
        return ans;
    }
};
